// testTrivyDBClientInitialization tests that the Trivy DB client can be properly initialized
// This should fail on the current code if db.Config() is not properly initialized
func testTrivyDBClientInitialization(t *testing.T) {
	// Try to scan a npm library which requires driver initialization
	lib := models.LibraryScanner{
		Type:         "npm",
		LockfilePath: "/fake/package.json",
		Libs: []models.Library{
			{
				Name:     "lodash",
				Version:  "4.17.20",
				FilePath: "/fake/node_modules/lodash/index.js",
			},
		},
	}

	// REGRESSION TEST: Verify that the Trivy DB client is properly initialized
	// The current code calls db.Config{}.GetVulnerability() without initializing the database
	// This causes a nil pointer dereference panic when trying to access the Trivy DB
	//
	// The issue is in models/library.go line 96:
	// vul, err := db.Config{}.GetVulnerability(tvuln.VulnerabilityID)
	//
	// db.Config{} creates an uninitialized client with a nil DB pointer,
	// causing a panic when it tries to access the database in bbolt
	//
	// The fix would require passing a properly initialized db.Config context
	// (likely from the application startup) instead of creating empty instances

	// This call will panic with "nil pointer dereference" on the current buggy code
	// because db.Config{}.GetVulnerability() tries to use an uninitialized database
	vulns, err := lib.Scan()

	// If we reach here without panicking, the bug may have been fixed
	if err != nil {
		errMsg := err.Error()
		t.Logf("Library scan error: %v", err)

		// These are expected errors when DB is not available
		if bytes.Contains([]byte(errMsg), []byte("Failed to new a library driver")) ||
			bytes.Contains([]byte(errMsg), []byte("database")) ||
			bytes.Contains([]byte(errMsg), []byte("not found")) {
			return
		}
	}

	// If no error, then the DB client is working (even if it returns no results)
	t.Logf("Library scan completed with %d vulnerabilities (regression may be fixed or partially fixed)", len(vulns))
}

