	// The test verifies that the Trivy DB client initialization doesn't fail with API mismatches
	vulns, err := lib.Scan()

	// We expect either:
	// 1. Successful scan (if DB is available) - then vulns should be empty or have results
	// 2. Error about missing database - that's OK
	// 3. BUT NOT an error about wrong API parameters to db.Config

	if err != nil {
		errMsg := err.Error()
		// Check for the specific error that would indicate Trivy DB API parameter mismatch
		// The old API was: db.Config{}.GetVulnerability(cveID)
		// If this changed to require additional context parameters, we'd see certain errors

		// Log the error for inspection
		t.Logf("Library scan error (may be expected): %v", err)

		// The error "Failed to new a library driver npm" means the driver couldn't be created
		// This is acceptable - it means the library driver system works but npm driver isn't available
		if bytes.Contains([]byte(errMsg), []byte("Failed to new a library driver")) {
			// This is acceptable - driver system works but driver unavailable
			return
		}

		// Other errors about missing DB are also acceptable
		if bytes.Contains([]byte(errMsg), []byte("database")) ||
			bytes.Contains([]byte(errMsg), []byte("not found")) {
			return
		}

		// If we get here, check for API parameter mismatch errors
		if bytes.Contains([]byte(errMsg), []byte("wrong number")) ||
			bytes.Contains([]byte(errMsg), []byte("not enough arguments")) ||
			bytes.Contains([]byte(errMsg), []byte("too many arguments")) ||
			bytes.Contains([]byte(errMsg), []byte("unexpected")) {
			t.Fatalf("REGRESSION: Trivy DB client API parameter mismatch detected: %v", err)
		}
	} else {
		// No error - scan succeeded or found no vulnerabilities
		// This is fine
		t.Logf("Library scan completed successfully with %d vulnerabilities", len(vulns))
	}
}

