   144→func (l *base) allContainers() (containers []config.Container, err error) {
   145→	switch l.ServerInfo.ContainerType {
   146→	case "", "docker":
   147→		stdout, err := l.dockerPs("-a --format '{{.ID}} {{.Names}} {{.Image}}'")
   148→		if err != nil {
   149→			return containers, err
   150→		}
   151→		return l.parseDockerPs(stdout)
   152→	case "lxd":
   153→		stdout, err := l.lxdPs("-c n")
   154→		if err != nil {
   155→			return containers, err
   156→		}
   157→		return l.parseLxdPs(stdout)
   158→	case "lxc":
   159→		stdout, err := l.lxcPs("-1")
   160→		if err != nil {
   161→			return containers, err
   162→		}
   163→		return l.parseLxcPs(stdout)
   164→	default:
   165→		return containers, xerrors.Errorf(
   166→			"Not supported yet: %s", l.ServerInfo.ContainerType)
   167→	}
   168→}
