   304→// ip executes ip command and returns IP addresses
   305→func (l *base) ip() ([]string, []string, error) {
   306→	// e.g.
   307→	// 2: eth0: <BROADCAST,MULTICAST,UP,LOWER_UP> mtu 1500 qdisc pfifo_fast state UP qlen 1000\    link/ether 52:54:00:2a:86:4c brd ff:ff:ff:ff:ff:ff
   308→	// 2: eth0    inet 10.0.2.15/24 brd 10.0.2.255 scope global eth0
   309→	// 2: eth0    inet6 fe80::5054:ff:fe2a:864c/64 scope link \       valid_lft forever preferred_lft forever
   310→	r := l.exec("/sbin/ip -o addr", noSudo)
   311→	if !r.isSuccess() {
   312→		return nil, nil, xerrors.Errorf("Failed to detect IP address: %v", r)
   313→	}
   314→	ipv4Addrs, ipv6Addrs := l.parseIP(r.Stdout)
   315→	return ipv4Addrs, ipv6Addrs, nil
   316→}
   317→
   318→// parseIP parses the results of ip command
   319→func (l *base) parseIP(stdout string) (ipv4Addrs []string, ipv6Addrs []string) {
   320→	lines := strings.Split(stdout, "\n")
   321→	for _, line := range lines {
   322→		fields := strings.Fields(line)
   323→		if len(fields) < 4 {
   324→			continue
   325→		}
   326→		ip, _, err := net.ParseCIDR(fields[3])
   327→		if err != nil {
   328→			continue
   329→		}
   330→		if !ip.IsGlobalUnicast() {
   331→			continue
   332→		}
   333→		if ipv4 := ip.To4(); ipv4 != nil {
   334→			ipv4Addrs = append(ipv4Addrs, ipv4.String())
   335→		} else {
   336→			ipv6Addrs = append(ipv6Addrs, ip.String())
   337→		}
   338→	}
   339→	return
   340→}
