   510→const (
   511→	systemd  = "systemd"
   512→	upstart  = "upstart"
   513→	sysVinit = "init"
   514→)
   515→
   516→// https://unix.stackexchange.com/questions/196166/how-to-find-out-if-a-system-uses-sysv-upstart-or-systemd-initsystem
   517→func (l *base) detectInitSystem() (string, error) {
   518→	var f func(string) (string, error)
   519→	f = func(cmd string) (string, error) {
   520→		r := l.exec(cmd, sudo)
   521→		if !r.isSuccess() {
   522→			return "", xerrors.Errorf("Failed to stat %s: %s", cmd, r)
   523→		}
   524→		scanner := bufio.NewScanner(strings.NewReader(r.Stdout))
   525→		scanner.Scan()
   526→		line := strings.TrimSpace(scanner.Text())
   527→		if strings.Contains(line, "systemd") {
   528→			return systemd, nil
   529→		} else if strings.Contains(line, "upstart") {
   530→			return upstart, nil
   531→		} else if strings.Contains(line, "File: ‘/proc/1/exe’ -> ‘/sbin/init’") ||
   532→			strings.Contains(line, "File: `/proc/1/exe' -> `/sbin/init'") {
   533→			return f("stat /sbin/init")
   534→		} else if line == "File: ‘/sbin/init’" ||
   535→			line == "File: `/sbin/init'" {
   536→			r := l.exec("/sbin/init --version", noSudo)
   537→			if r.isSuccess() {
   538→				if strings.Contains(r.Stdout, "upstart") {
   539→					return upstart, nil
   540→				}
   541→			}
   542→			return sysVinit, nil
   543→		}
   544→		return "", xerrors.Errorf("Failed to detect a init system: %s", line)
   545→	}
   546→	return f("stat /proc/1/exe")
   547→}
