   569→// LibFile : library file content
   570→type LibFile struct {
   571→	Contents []byte
   572→	Filemode os.FileMode
   573→}
   574→
   575→func (l *base) scanLibraries() (err error) {
   576→	if len(l.LibraryScanners) != 0 {
   577→		return nil
   578→	}
   579→
   580→	// library scan for servers need lockfiles
   581→	if len(l.ServerInfo.Lockfiles) == 0 && !l.ServerInfo.FindLock {
   582→		return nil
   583→	}
   584→
   585→	l.log.Info("Scanning Lockfile...")
   586→
   587→	libFilemap := map[string]LibFile{}
   588→	detectFiles := l.ServerInfo.Lockfiles
   589→
   590→	// auto detect lockfile
   591→	if l.ServerInfo.FindLock {
   592→		findopt := ""
   593→		for filename := range models.LibraryMap {
   594→			findopt += fmt.Sprintf("-name %q -o ", filename)
   595→		}
   596→
   597→		// delete last "-o "
   598→		// find / -type f -and \( -name "package-lock.json" -o -name "yarn.lock" ... \) 2>&1 | grep -v "find: "
   599→		cmd := fmt.Sprintf(`find / -type f -and \( ` + findopt[:len(findopt)-3] + ` \) 2>&1 | grep -v "find: "`)
   600→		r := exec(l.ServerInfo, cmd, noSudo)
   601→		if r.ExitStatus != 0 && r.ExitStatus != 1 {
   602→			return xerrors.Errorf("Failed to find lock files")
   603→		}
   604→		detectFiles = append(detectFiles, strings.Split(r.Stdout, "\n")...)
   605→	}
   606→
   607→	for _, path := range detectFiles {
   608→		if path == "" {
   609→			continue
   610→		}
   611→
   612→		if path, err = filepath.Abs(path); err != nil {
   613→			return xerrors.Errorf("Failed to abs the lockfile. err: %w, filepath: %s", err, path)
   614→		}
   615→
   616→		// skip already exist
   617→		if _, ok := libFilemap[path]; ok {
   618→			continue
   619→		}
   620→
   621→		var f LibFile
   622→		switch l.Distro.Family {
   623→		case constant.ServerTypePseudo:
   624→			fileinfo, err := os.Stat(path)
   625→			if err != nil {
   626→				return xerrors.Errorf("Failed to get target file info. err: %w, filepath: %s", err, path)
   627→			}
   628→			f.Filemode = fileinfo.Mode().Perm()
   629→			f.Contents, err = os.ReadFile(path)
   630→			if err != nil {
   631→				return xerrors.Errorf("Failed to read target file contents. err: %w, filepath: %s", err, path)
   632→			}
   633→		default:
   634→			cmd := fmt.Sprintf(`stat -c "%%a" %s`, path)
   635→			r := exec(l.ServerInfo, cmd, noSudo)
   636→			if !r.isSuccess() {
   637→				return xerrors.Errorf("Failed to get target file permission: %s, filepath: %s", r, path)
   638→			}
   639→			permStr := fmt.Sprintf("0%s", strings.ReplaceAll(r.Stdout, "\n", ""))
   640→			perm, err := strconv.ParseUint(permStr, 8, 32)
   641→			if err != nil {
   642→				return xerrors.Errorf("Failed to parse permission string. err: %w, permission string: %s", err, permStr)
   643→			}
   644→			f.Filemode = os.FileMode(perm)
   645→
   646→			cmd = fmt.Sprintf("cat %s", path)
   647→			r = exec(l.ServerInfo, cmd, noSudo)
   648→			if !r.isSuccess() {
   649→				return xerrors.Errorf("Failed to get target file contents: %s, filepath: %s", r, path)
   650→			}
   651→			f.Contents = []byte(r.Stdout)
   652→		}
   653→		libFilemap[path] = f
   654→	}
   655→
   656→	var libraryScanners []models.LibraryScanner
   657→	if libraryScanners, err = AnalyzeLibraries(context.Background(), libFilemap, l.ServerInfo.Mode.IsOffline()); err != nil {
   658→		return err
   659→	}
   660→	l.LibraryScanners = append(l.LibraryScanners, libraryScanners...)
   661→	return nil
   662→}
   663→
   664→// AnalyzeLibraries : detects libs defined in lockfile
   665→func AnalyzeLibraries(ctx context.Context, libFilemap map[string]LibFile, isOffline bool) (libraryScanners []models.LibraryScanner, err error) {
   666→	disabledAnalyzers := []analyzer.Type{
   667→		analyzer.TypeAlpine,
   668→		analyzer.TypeAlma,
   669→		analyzer.TypeAmazon,
   670→		analyzer.TypeDebian,
   671→		analyzer.TypePhoton,
   672→		analyzer.TypeCentOS,
   673→		analyzer.TypeFedora,
   674→		analyzer.TypeOracle,
   675→		analyzer.TypeRedHatBase,
   676→		analyzer.TypeRocky,
   677→		analyzer.TypeSUSE,
   678→		analyzer.TypeUbuntu,
   679→		analyzer.TypeApk,
   680→		analyzer.TypeDpkg,
   681→		analyzer.TypeRpm,
   682→		analyzer.TypeApkCommand,
   683→		analyzer.TypeYaml,
   684→		analyzer.TypeTOML,
   685→		analyzer.TypeJSON,
   686→		analyzer.TypeDockerfile,
   687→		analyzer.TypeHCL,
   688→		analyzer.TypeSecret,
   689→	}
   690→	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)
   691→
   692→	for path, f := range libFilemap {
   693→		var wg sync.WaitGroup
   694→		result := new(analyzer.AnalysisResult)
   695→		if err := anal.AnalyzeFile(
   696→			ctx,
   697→			&wg,
   698→			semaphore.NewWeighted(1),
   699→			result,
   700→			"",
   701→			path,
   702→			&DummyFileInfo{size: int64(len(f.Contents)), filemode: f.Filemode},
   703→			func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader(f.Contents)), nil },
   704→			nil,
   705→			analyzer.AnalysisOptions{Offline: isOffline},
   706→		); err != nil {
   707→			return nil, xerrors.Errorf("Failed to get libs. err: %w", err)
   708→		}
   709→		wg.Wait()
   710→
   711→		libscan, err := convertLibWithScanner(result.Applications)
   712→		if err != nil {
   713→			return nil, xerrors.Errorf("Failed to convert libs. err: %w", err)
   714→		}
   715→		libraryScanners = append(libraryScanners, libscan...)
   716→	}
   717→	return libraryScanners, nil
   718→}
