   944→func nativeScanPort(scanDest string) (bool, error) {
   945→	conn, err := net.DialTimeout("tcp", scanDest, time.Duration(1)*time.Second)
   946→	if err != nil {
   947→		if strings.Contains(err.Error(), "i/o timeout") || strings.Contains(err.Error(), "connection refused") {
   948→			return false, nil
   949→		}
   950→		if strings.Contains(err.Error(), "too many open files") {
   951→			time.Sleep(time.Duration(1) * time.Second)
   952→			return nativeScanPort(scanDest)
   953→		}
   954→		return false, err
   955→	}
   956→	conn.Close()
   957→
   958→	return true, nil
   959→}
