  1222→	for pid := range pidNames {
  1223→		stdout := ""
  1224→		stdout, err = l.lsProcExe(pid)
  1225→		if err != nil {
  1226→			l.log.Debugf("Failed to exec ls -l /proc/%s/exe err: %+v", pid, err)
  1227→			continue
  1228→		}
  1229→		s, err := l.parseLsProcExe(stdout)
  1230→		if err != nil {
  1231→			l.log.Debugf("Failed to parse /proc/%s/exe: %+v", pid, err)
  1232→			continue
  1233→		}
  1234→		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], s)
  1235→
  1236→		stdout, err = l.grepProcMap(pid)
  1237→		if err != nil {
  1238→			l.log.Debugf("Failed to exec /proc/%s/maps: %+v", pid, err)
  1239→			continue
  1240→		}
  1241→		ss := l.parseGrepProcMap(stdout)
  1242→		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], ss...)
  1243→	}
  1244→
  1245→	pidListenPorts := map[string][]models.PortStat{}
  1246→	stdout, err = l.lsOfListen()
  1247→	if err != nil {
  1248→		// warning only, continue scanning
  1249→		l.log.Warnf("Failed to lsof: %+v", err)
  1250→	}
  1251→	portPids := l.parseLsOf(stdout)
  1252→	for ipPort, pids := range portPids {
  1253→		for _, pid := range pids {
  1254→			portStat, err := models.NewPortStat(ipPort)
  1255→			if err != nil {
  1256→				l.log.Warnf("Failed to parse ip:port: %s, err: %+v", ipPort, err)
  1257→				continue
  1258→			}
  1259→			pidListenPorts[pid] = append(pidListenPorts[pid], *portStat)
  1260→		}
  1261→	}
  1262→
  1263→	for pid, loadedFiles := range pidLoadedFiles {
  1264→		pkgNames, err := getOwnerPkgs(loadedFiles)
  1265→		if err != nil {
  1266→			l.log.Warnf("Failed to get owner pkgs of: %s", loadedFiles)
  1267→			continue
  1268→		}
  1269→		uniq := map[string]struct{}{}
  1270→		for _, name := range pkgNames {
  1271→			uniq[name] = struct{}{}
  1272→		}
  1273→
  1274→		procName := ""
  1275→		if _, ok := pidNames[pid]; ok {
  1276→			procName = pidNames[pid]
  1277→		}
  1278→		proc := models.AffectedProcess{
  1279→			PID:             pid,
  1280→			Name:            procName,
  1281→			ListenPortStats: pidListenPorts[pid],
  1282→		}
  1283→
  1284→		for name := range uniq {
  1285→			p, ok := l.Packages[name]
  1286→			if !ok {
  1287→				l.log.Warnf("Failed to find a running pkg: %s", name)
  1288→				continue
  1289→			}
  1290→			p.AffectedProcs = append(p.AffectedProcs, proc)
  1291→			l.Packages[p.Name] = p
  1292→		}
  1293→	}
  1294→	return nil
  1295→}
