// TestRegression verifies the library scanner failures are caught
func TestRegression(t *testing.T) {
	t.Run("TrivyDBClientInitializationFailure", testTrivyDBClientInitialization)
	t.Run("MissingPackageEcosystems", testMissingPackageEcosystems)
	t.Run("IncompleteAnalyzerScope", testIncompleteAnalyzerScope)
	t.Run("StaleImportPath", testStaleImportPath)
}

// testTrivyDBClientInitialization tests that the Trivy DB client can be properly initialized
// This should fail on the current code if db.Config().GetVulnerability() has incompatible API
func testTrivyDBClientInitialization(t *testing.T) {
	// Try to scan a npm library which requires driver initialization
	lib := models.LibraryScanner{
		Type:         "npm",
		LockfilePath: "/fake/package.json",
		Libs: []models.Library{
			{
				Name:     "lodash",
				Version:  "4.17.20",
				FilePath: "/fake/node_modules/lodash/index.js",
			},
		},
	}

	// This call should invoke library.NewDriver() and db.Config{}.GetVulnerability() internally
	// The test verifies that the Trivy DB client initialization doesn't fail with API mismatches
	vulns, err := lib.Scan()

	// We expect either:
	// 1. Successful scan (if DB is available) - then vulns should be empty or have results
	// 2. Error about missing database - that's OK
	// 3. BUT NOT an error about wrong API parameters to db.Config

	if err != nil {
		errMsg := err.Error()
		// Check for the specific error that would indicate Trivy DB API parameter mismatch
		// The old API was: db.Config{}.GetVulnerability(cveID)
		// If this changed to require additional context parameters, we'd see certain errors

		// Log the error for inspection
		t.Logf("Library scan error (may be expected): %v", err)

		// The error "Failed to new a library driver npm" means the driver couldn't be created
		// This is acceptable - it means the library driver system works but npm driver isn't available
		if bytes.Contains([]byte(errMsg), []byte("Failed to new a library driver")) {
			// This is acceptable - driver system works but driver unavailable
			return
		}

		// Other errors about missing DB are also acceptable
		if bytes.Contains([]byte(errMsg), []byte("database")) ||
			bytes.Contains([]byte(errMsg), []byte("not found")) {
			return
		}

		// If we get here, check for API parameter mismatch errors
		if bytes.Contains([]byte(errMsg), []byte("wrong number")) ||
			bytes.Contains([]byte(errMsg), []byte("not enough arguments")) ||
			bytes.Contains([]byte(errMsg), []byte("too many arguments")) ||
			bytes.Contains([]byte(errMsg), []byte("unexpected")) {
			t.Fatalf("REGRESSION: Trivy DB client API parameter mismatch detected: %v", err)
		}
	} else {
		// No error - scan succeeded or found no vulnerabilities
		// This is fine
		t.Logf("Library scan completed successfully with %d vulnerabilities", len(vulns))
	}
}

// testMissingPackageEcosystems tests that PNPM and other newer package managers are not supported
// This test verifies that the LibraryMap is missing entries for PNPM and .NET package lock files
// which is the regression we're testing for
func testMissingPackageEcosystems(t *testing.T) {
	const (
		pnpmLockFilename = "pnpm-lock.yaml"
	)

	// REGRESSION TEST: Check if PNPM ecosystem is missing from the library map
	// Users report that PNPM lockfiles result in zero vulnerability findings
	// despite having known vulnerable dependencies
	if _, hasPNPM := models.LibraryMap[pnpmLockFilename]; !hasPNPM {
		t.Fatalf("REGRESSION DETECTED: PNPM lockfile (%s) not in LibraryMap - projects using PNPM will have zero vulnerability findings", pnpmLockFilename)
	}

	// REGRESSION TEST: Verify that known package managers are properly mapped
	requiredMappings := map[string]string{
		"pnpm-lock.yaml":     "pnpm",
		"Gemfile.lock":       "ruby",
		"package-lock.json":  "node",
		"yarn.lock":          "node",
		"Cargo.lock":         "rust",
		"composer.lock":      "php",
		"poetry.lock":        "python",
		"requirements.txt":   "python",
		"packages.lock.json": ".net",
	}

	var missingEcosystems []string
	for filename, expectedType := range requiredMappings {
		got, exists := models.LibraryMap[filename]
		if !exists {
			t.Logf("REGRESSION: Missing mapping for %s (expected type: %s)", filename, expectedType)
			missingEcosystems = append(missingEcosystems, filename)
		} else if got != expectedType {
			t.Errorf("Wrong mapping for %s: got %s, expected %s", filename, got, expectedType)
		}
	}

	if len(missingEcosystems) > 0 {
		t.Fatalf("REGRESSION DETECTED: %d package ecosystems not properly mapped: %v", len(missingEcosystems), missingEcosystems)
	}
}

