		}
	}

	if unsupportedCount > 0 {
		t.Logf("Found %d unsupported package ecosystems", unsupportedCount)
	}
}

// TestMultipleLibraryVulnerabilityScan tests scanning multiple libraries with different ecosystems
func TestMultipleLibraryVulnerabilityScan(t *testing.T) {
	// Test scanning multiple library types
	testCases := []struct {
		name    string
		libType string
		pkgName string
		pkgVer  string
	}{
		{"npm-lodash", "npm", "lodash", "4.17.20"},
		{"pip-django", "pip", "django", "2.2.0"},
		{"ruby-bundler", "ruby", "rails", "5.2.0"},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			lib := models.LibraryScanner{
				Type:         tc.libType,
				LockfilePath: "/test/lockfile",
				Libs: []models.Library{
					{
						Name:    tc.pkgName,
						Version: tc.pkgVer,
					},
				},
			}

			vulns, panicMsg := SafeLibraryScan(lib)
			if panicMsg != "" && bytes.Contains([]byte(panicMsg), []byte("nil")) {
				t.Logf("REGRESSION: Nil pointer dereference when scanning %s library: %s", tc.libType, panicMsg)
			} else if panicMsg != "" {
				t.Logf("Panic during scan: %s", panicMsg)
			} else {
				t.Logf("Scan completed with %d vulnerabilities", len(vulns))
			}
		})
	}
}

// TestPNPMPackageManagerSupport tests that PNPM lockfiles are properly handled
func TestPNPMPackageManagerSupport(t *testing.T) {
	// REGRESSION TEST: PNPM is a popular package manager but not in LibraryMap
	// This causes projects using PNPM to have zero vulnerability findings

	pnpmLockFilename := "pnpm-lock.yaml"
	pnpmType := "pnpm"

	if _, exists := models.LibraryMap[pnpmLockFilename]; !exists {
		t.Logf("REGRESSION: %s not mapped to %s in LibraryMap", pnpmLockFilename, pnpmType)
		t.Logf("Users report: Projects using PNPM have zero vulnerability findings despite known vulnerable dependencies")
	} else {
		t.Logf("PNPM support found in LibraryMap")
	}

	// Also check for other missing Node.js package managers
	nodePkgManagers := map[string]string{
		"pnpm-lock.yaml": "pnpm",
		"bun.lock":       "bun",
		"npm-shrinkwrap.json": "npm",  // This might be missing too
	}

	for filename, pkgMgr := range nodePkgManagers {
		if _, exists := models.LibraryMap[filename]; !exists {
			t.Logf("Missing Node.js package manager support: %s (%s)", filename, pkgMgr)
		}
	}
}

// TestDotNETPackageSupport tests that .NET package dependency files are mapped correctly
func TestDotNETPackageSupport(t *testing.T) {
	// Test for .NET package manager support
	dotnetLockFiles := map[string]string{
		"packages.lock.json":   ".net",
		"packages.config":      ".net",
		"project.assets.json":  ".net",  // Newer format from NuGet
	}

	missingFormats := []string{}
	for filename, expectedType := range dotnetLockFiles {
		if actualType, exists := models.LibraryMap[filename]; !exists {
			t.Logf("Missing .NET lockfile support: %s (type: %s)", filename, expectedType)
			missingFormats = append(missingFormats, filename)
		} else if actualType != expectedType {
			t.Logf("Wrong .NET mapping: %s -> got %s, expected %s", filename, actualType, expectedType)
		}
	}

	if len(missingFormats) > 0 {
		t.Logf("REGRESSION: Missing %d .NET package dependency file formats", len(missingFormats))
	}
}
